import { useContext } from "react";
import { TodoContext } from "../TodoContext";
import { TodoSearch } from "../components/TodoSearch";
import { TodoContainer } from "../components/TodoContainer";
import { TodoTask } from "../components/TodoTask";
import { Modal } from "../Modal";
import { ButtonLaunchModal } from "../components/ButtonLaunchModal";
import { TodoInput } from "../components/TodoInput";

enum type { remove, edit, toggleStatus };

const AppUI = () => {
    const {
        totalTodos,
        completedTodos,
        todosRendered,
        handleTodo,
        modalState,
    } = useContext(TodoContext);
    return (
        <main className="App">
            <h1>Todo App</h1>
            <p style={{ color: "white" }}>
                {completedTodos} of {totalTodos} todos completed
            </p>
            <TodoSearch />
            <TodoContainer>
                {todosRendered.map((todo) => (
                    <TodoTask
                        key={todo.id}
                        id={todo.id}
                        content={todo.description}
                        status={todo.status}
                        handleTodo={(id: number,type:type) => handleTodo(id,type)}
                    />
                ))}
            </TodoContainer>
            <ButtonLaunchModal className="btn__add-todo">
                +
            </ButtonLaunchModal>
            {modalState && (
                <Modal>
                    <TodoInput description="hola"/>
                </Modal>
            )}
        </main>
    );
};

export { AppUI };
