import { useContext, useEffect, useState } from "react";
import { Task } from "../interfaces";
import { TodoContext } from "../TodoContext";

interface IProps { description: string }

const TodoInput: React.FC<IProps> = ({description}) => {
    const { totalTodos,addTodo,isEdit } = useContext(TodoContext);
    const [newTask, setNewTask] = useState<string>("");

    const registerTask = (e: React.SyntheticEvent): void => {
        e.preventDefault();
        const description = newTask;
        const newTodo: Task = {
            id: totalTodos + new Date().getTime()/1000,
            description,
            status: false
        }
        addTodo({...newTodo});
    };
    useEffect( () => {
        if(isEdit) {
            setNewTask(description)
        }
    },[] )

    return (
        <section className="todo-input">
            <form onSubmit={registerTask}>
                <label htmlFor="task-input" className="task-input">
                    Type a new Task
                </label>
                <textarea
                    id="task-input"
                    placeholder="To wash the Beaver"
                    name="task-input"
                    value={newTask}
                    onChange={(e) => setNewTask(e.target.value)}
                />
                <button>Add Task!</button>
            </form>
        </section>
    );
};

export { TodoInput };
