import { useEffect, useState } from "react";
import { Task } from "../interfaces";

interface IStorage {
    item:Task[];
    saveItem: (newItem:Task[]) => void;
    loading: boolean;
}
// const tasks: Task[] = [
//     { id: 1, description: "First Task", status: true },
//     { id: 2, description: "Second Task", status: true },
//     { id: 3, description: "Third Task", status: false },
//     { id: 4, description: "Four Task", status: true },
// ];

const useLocalStorage = (itemName: string):IStorage => {
    const [loading, setLoading] = useState<boolean>(true);
    const [item, setItem] = useState<Task[]>([]);

    useEffect(() => {
        const dataStored = localStorage.getItem(itemName);
        setTimeout(() => {
            const tasks: Task[] = dataStored ? JSON.parse(dataStored) : [];
            setItem(tasks);
            setLoading(false);
        }, 3000);
    },[]);
    const saveItem = (newItem: Task[]) => {
        const dataToString = JSON.stringify(newItem);
        localStorage.setItem(itemName, dataToString);
        setItem(newItem);
    };

    return {item,saveItem,loading}
};

export { useLocalStorage };
