const TodoSearch: React.FC = () => {
    // const [search, setSearch] = useState<string>("");
    const {searchTodo,todoSearched} = useContext(TodoContext);
    return (
        <section className="todo-search">
            <h2>Search</h2>
            <label htmlFor="search">Looking for your tasks!</label>
            <input
                id="search"
                type="text"
                placeholder="Something about work, maybe?"
                value={todoSearched}
                onChange={searchTodo}
            />
            <pre>{todoSearched}</pre>
        </section>
    );
};
export { TodoSearch };
