import React, { createContext, useState } from "react";
import { useLocalStorage } from "./useLocalStorage";
import { Task } from "../interfaces";

enum type { remove, edit, toggleStatus };

interface IValue {
    loading: boolean;
    totalTodos: number;
    completedTodos: number;
    todoSearched: string;
    todosRendered: Task[];
    modalState: boolean;
    isEdit:boolean;
    setModalState: React.Dispatch<React.SetStateAction<boolean>>;
    searchTodo: (e: React.FormEvent<HTMLInputElement>) => void;
    addTodo: (todo:Task) => void;
    handleTodo: (id:number, type:type) => void;
    handleTodoToEdit: (id:number) => void;
}

const DefaultValues: IValue = {
    loading: true,
    totalTodos: 0,
    completedTodos: 0,
    todoSearched: "",
    todosRendered: [],
    modalState: false,
    isEdit:false,
    setModalState: () => 0,
    searchTodo: () => 0,
    addTodo: () => 0,
    handleTodo: () => 0,
    handleTodoToEdit: () => 0
}

const TodoContext = createContext<IValue>(DefaultValues);

const TodoProvider = ({ children }: any) => {
    const [todoSearched, setTodoSearched] = useState<string>("");
    const [modalState, setModalState] = useState<boolean>(false);
    const [isEdit,setIsEdit] = useState<boolean>(false);

    const storage_values = useLocalStorage("TODOS_V1");
    const { item: todos, saveItem: saveTodos, loading } = storage_values;
    const totalTodos: number = todos.length;
    const completedTodos: number = todos.reduce(
        (acc, todo) => acc + (todo.status ? 1 : 0),
        0
    );
    const todosRendered: Task[] = todos.filter((todo) => {
        const description: string = todo.description.toLowerCase();
        const search: string = todoSearched.toLowerCase();
        return description.includes(search);
    });

    const searchTodo = (e: React.FormEvent<HTMLInputElement>): void => {
        const { value } = e.target as HTMLInputElement;
        setTodoSearched(value);
    };
    const toggleTodoStatus = (id: number) => {
        const todosUpToDate: Task[] = todos.map((todo) =>
            todo.id === id ? { ...todo, status: !todo.status } : { ...todo }
        );
        saveTodos(todosUpToDate);
    };

    const removeTodo = (id: number): void => {
        const index: number = todos.findIndex((todo) => todo.id === id);
        const todosUpToDate: Task[] = todos.map((todo) => ({ ...todo }));
        todosUpToDate.splice(index, 1);
        saveTodos(todosUpToDate);
    };

    const addTodo = (todo: Task) => {
        const todosUpToDate: Task[] = todos.map((todo) => ({ ...todo }));
        todosUpToDate.push(todo);
        saveTodos(todosUpToDate);
    };
    const editTodo = (id: number, todoEdited:Task) => {
        const { description } = todoEdited;
        const index: number = todos.findIndex((todo) => todo.id === id);
        const todosUpToDate: Task[] = todos.map((todo) => ({ ...todo }));
        const todoToEdit = todosUpToDate[index];
        todoToEdit.description = description;
        saveTodos(todosUpToDate);

    };
    const handleTodoToEdit = (id:number) => {
        console.log(id)
    }

    const handleTodo = (id:number,ptype:type) =>{
        switch (ptype) {
            case (type.remove):
                removeTodo(id);
                break;
            case (type.toggleStatus):
                toggleTodoStatus(id);
        }
    }
    return (
        <TodoContext.Provider
            value={{
                loading,
                totalTodos,
                completedTodos,
                searchTodo,
                modalState,
                isEdit,
                setModalState,
                todoSearched,
                todosRendered,
                addTodo,
                handleTodo,
                handleTodoToEdit,
            }}
        >
            {children}
        </TodoContext.Provider>
    );
};

export { TodoContext, TodoProvider };
