import React, { useContext } from "react";
import { TodoContext } from "../TodoContext";
interface IProps {
    className: string;
    children: React.ReactNode;
    todoId?: number;
}
function ButtonLaunchModal(props: IProps) {
    const { modalState, setModalState, handleTodoToEdit } =
        useContext(TodoContext);
    const toggleModal = (): void => {
        setModalState(!modalState);
        if (props.todoId !== undefined) {
            handleTodoToEdit(props.todoId);
        }
    };

    return (
        <button
            className={`${props.className} ${modalState && "active"}`}
            onClick={toggleModal}
        >
            {props.children}
        </button>
    );
}

export { ButtonLaunchModal };
