import React,{useContext} from "react";
import { ButtonLaunchModal } from "./ButtonLaunchModal";

enum type { remove, edit, toggleStatus };

interface Props {
    id: number;
    content: string;
    status: boolean;
    handleTodo: (id:number,type:type) => void;
}
const TodoTask: React.FC<Props> = (props) => {
    const setFinishedColor = props.status?"is-finished":"";
    const setIconStatus = props.status?"fas fa-check-circle":"fas fa-circle-notch"

    return (
        <React.Fragment>
            <li className="todo-task">
                <span className={`todo-task__content ${setFinishedColor}`}>
                    <span
                        onClick={() => props.handleTodo(props.id, type.toggleStatus)}
                        className={setIconStatus}
                    ></span>
                    {props.content}
                </span>
                <span className="fas fa-times-circle" onClick={() => props.handleTodo(props.id, type.remove)}></span>
                <ButtonLaunchModal className="todo-task__edit" todoId={props.id}>edit</ButtonLaunchModal>
            </li>
        </React.Fragment>
    );
};

export { TodoTask };
